'use client'

import { useState, useEffect } from 'react'
import gsap from 'gsap'
import styles from './DonationModal.module.css'

export default function DonationModal() {
  const [isOpen, setIsOpen] = useState(false)

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden'
      gsap.fromTo(
        '.donation-modal-content',
        { opacity: 0, scale: 0.9, y: 50 },
        { opacity: 1, scale: 1, y: 0, duration: 0.4, ease: 'back.out(1.7)' }
      )
      gsap.fromTo(
        '.donation-modal-overlay',
        { opacity: 0 },
        { opacity: 1, duration: 0.3 }
      )
    } else {
      document.body.style.overflow = 'unset'
    }

    return () => {
      document.body.style.overflow = 'unset'
    }
  }, [isOpen])

  const handleClose = () => {
    gsap.to('.donation-modal-content', {
      opacity: 0,
      scale: 0.9,
      y: 50,
      duration: 0.3,
      ease: 'power3.in',
      onComplete: () => setIsOpen(false)
    })
    gsap.to('.donation-modal-overlay', {
      opacity: 0,
      duration: 0.3
    })
  }

  const handleEscKey = (e: KeyboardEvent) => {
    if (e.key === 'Escape') handleClose()
  }

  useEffect(() => {
    if (isOpen) {
      window.addEventListener('keydown', handleEscKey)
      return () => window.removeEventListener('keydown', handleEscKey)
    }
  }, [isOpen])

  return (
    <>
      <button
        className={styles.stickyButton}
        onClick={() => setIsOpen(true)}
        aria-label="Abrir formulario de donación"
      >
        <span className={styles.buttonIcon}>❤</span>
        Donaciones
      </button>

      {isOpen && (
        <div className={styles.modalOverlay} donation-modal-overlay>
          <div className={styles.modalWrapper}>
            <button
              className={styles.closeButton}
              onClick={handleClose}
              aria-label="Cerrar modal"
            >
              ✕
            </button>
            <div className={styles.modalContent} donation-modal-content>
              <iframe
                src="/donation-form"
                className={styles.iframe}
                title="Formulario de donación"
              />
            </div>
          </div>
        </div>
      )}
    </>
  )
}
